  signs: { left: ["Muscle weakness (asymmetric)", "Atrophy and fasciculations", "Dysarthria", "Dysphagia", "Hyperreflexia (UMN)"], right: ["Respiratory decline", "Weight loss", "Foot drop or hand weakness", "Spasticity", "Positive Babinski sign"] },
