  diagnostics: ["Perform facial symmetry assessment (raise eyebrows, close eyes, smile, puff cheeks)", "Differentiate from stroke: test forehead movement (affected in Bell palsy, spared in stroke)", "Assess corneal reflex on affected side", "Monitor ability to eat and drink (lip weakness causes drooling)", "Expect CT or MRI if stroke cannot be ruled out clinically", "Assess taste sensation on anterior tongue if feasible"],
  management: ["Administer corticosteroids within 72 hours of onset as prescribed", "Provide aggressive eye protection (artificial tears, lubricating ointment, eye patch at night)", "Teach facial exercises when recovery begins", "Apply moist heat to affected side for comfort", "Modify diet if needed (soft foods, straw may be difficult)", "Provide emotional support and reassurance about expected recovery"],
  nursingActions: ["Assess facial symmetry including forehead, eye closure, and smile", "Apply artificial tears every 1-2 hours to protect the cornea", "Tape or patch the affected eye at night to prevent corneal drying", "Administer prescribed corticosteroids and antivirals on schedule", "Assess ability to eat and drink safely (food may pocket in affected cheek)", "Provide emotional support and reassurance that most patients recover fully", "Teach patient to chew on unaffected side", "Document degree of facial weakness using House-Brackmann scale if applicable"],
  assessmentFindings: ["Sudden onset unilateral facial paralysis (entire half including forehead)", "Inability to close eye on affected side", "Drooping mouth corner with drooling", "Loss of nasolabial fold on affected side", "Decreased or absent taste on anterior two-thirds of tongue", "Hyperacusis (increased sensitivity to sound) from stapedius muscle paralysis", "Eye dryness from decreased lacrimation", "Difficulty eating and speaking"],
  signs: { left: ["Complete unilateral facial paralysis", "Cannot raise eyebrow on affected side", "Cannot close eye on affected side", "Mouth drooping with drooling", "Loss of nasolabial fold"], right: ["Hyperacusis", "Taste changes", "Eye dryness", "Difficulty chewing", "Speech changes"] },
  medications: [
    { name: "Prednisone", type: "Corticosteroid", action: "Reduces inflammation and edema of the facial nerve within the fallopian canal, improving nerve conduction recovery", sideEffects: "Hyperglycemia, insomnia, mood changes, GI irritation, immunosuppression", contra: "Active systemic infection, uncontrolled diabetes (use cautiously)", pearl: "Most effective when started within 72 hours of symptom onset; typical course is 60-80mg daily for 5 days followed by taper; single most important treatment to improve outcomes" },
    { name: "Acyclovir (Valtrex)", type: "Antiviral", action: "Inhibits herpes simplex virus DNA replication, targeting the presumed viral trigger of Bell palsy", sideEffects: "Nausea, headache, renal toxicity (ensure hydration)", contra: "Renal impairment (dose adjustment needed)", pearl: "Often prescribed in combination with prednisone based on the viral reactivation theory; evidence for benefit is modest but risk is low; ensure adequate fluid intake to prevent renal crystals" }
  ],
  pearls: ["Forehead involvement distinguishes Bell palsy (peripheral, entire face affected) from stroke (central, forehead spared)", "Corneal protection is the number one nursing priority: inability to close the eye can lead to corneal ulceration and vision loss", "85% of patients recover completely within 3-6 months", "Start corticosteroids within 72 hours for best outcomes", "Emotional support is important: sudden facial paralysis is distressing and affects self-image", "If forehead movement is preserved, investigate for stroke, not Bell palsy"],
  lifespan: { title: "Across the Lifespan", content: "Bell palsy can occur at any age but peaks between 15-45 years. Pregnant women in the third trimester and first postpartum week have three times the risk of the general population, possibly due to fluid retention compressing the nerve in the facial canal. Children with Bell palsy generally have excellent recovery rates (over 90% full recovery). In elderly patients, recovery may be slower and less complete, and the differential diagnosis should include stroke and tumor." },
