lessons["hydrocephalus-basics-rpn"] = {
  title: "Hydrocephalus Basics",
  cellular: { title: "Pathophysiology of Hydrocephalus", content: "Hydrocephalus is the abnormal accumulation of cerebrospinal fluid (CSF) within the ventricular system of the brain, causing ventricular dilation and increased intracranial pressure. Understanding CSF production, circulation, and absorption is essential for nurses managing patients with hydrocephalus or CSF diversion devices.\n\nCSF is produced primarily by the choroid plexus within the lateral ventricles at a rate of approximately 500 mL per day (20 mL/hour). The total CSF volume at any given time is only 125-150 mL, meaning the entire volume is replaced three to four times daily. CSF flows from the lateral ventricles through the foramen of Monro into the third ventricle, then through the cerebral aqueduct (aqueduct of Sylvius) into the fourth ventricle, and exits through the foramina of Luschka and Magendie into the subarachnoid space, where it is absorbed by arachnoid granulations (villi) into the venous sinuses.\n\nHydrocephalus develops when there is an imbalance between CSF production and absorption. There are three mechanisms: obstructive (non-communicating) hydrocephalus occurs when CSF flow is blocked within the ventricular system (commonly at the narrow cerebral aqueduct), caused by tumors, congenital stenosis, or blood clots. Communicating hydrocephalus occurs when CSF can flow through the ventricles but absorption by the arachnoid granulations is impaired, commonly caused by subarachnoid hemorrhage, meningitis, or fibrosis. Rarely, overproduction of CSF by a choroid plexus papilloma causes hydrocephalus.\n\nNormal pressure hydrocephalus (NPH) is a unique form seen in elderly patients characterized by the classic triad of gait disturbance (wide-based, magnetic gait), urinary incontinence, and dementia. Despite ventriculomegaly, ICP may be normal or only intermittently elevated. NPH is important because it is one of the few reversible causes of dementia when treated with CSF shunting.\n\nTreatment typically involves surgical placement of a ventriculoperitoneal (VP) shunt, which diverts CSF from the lateral ventricle through a subcutaneous catheter to the peritoneal cavity for absorption. Endoscopic third ventriculostomy (ETV) is an alternative for obstructive hydrocephalus.\n\nFor RPNs, critical responsibilities include recognizing signs of increased ICP, monitoring shunt function (signs of malfunction include headache, vomiting, decreased LOC, and bulging fontanelle in infants), maintaining shunt precautions (avoid positioning on the shunt valve side), and recognizing shunt infection (fever, redness along shunt tract, changes in mental status)." },
  riskFactors: ["Congenital aqueductal stenosis", "Neural tube defects (spina bifida, myelomeningocele)", "Prematurity with intraventricular hemorrhage", "Meningitis or CNS infection", "Subarachnoid hemorrhage", "Brain tumor obstructing CSF pathways", "Head trauma", "Age over 65 (normal pressure hydrocephalus)"],
  diagnostics: ["Expect CT scan showing dilated ventricles", "Expect MRI for detailed ventricular anatomy", "Monitor head circumference in infants (serial measurements above 95th percentile)", "Expect lumbar puncture with CSF removal trial in suspected NPH", "Monitor ICP if invasive monitoring is placed", "Assess for signs of shunt malfunction post-operatively"],
  management: ["Maintain prescribed positioning after shunt placement (typically flat or low HOB initially)", "Monitor for shunt malfunction signs (headache, vomiting, decreased LOC, bulging fontanelle)", "Monitor for shunt infection signs (fever, redness along shunt tract, irritability)", "Do not pump the shunt valve unless specifically ordered", "Implement seizure precautions post-operatively", "Monitor wound site for CSF leak or infection"],
  nursingActions: ["Measure head circumference daily in infants and plot on growth chart", "Assess for signs of increased ICP at every assessment", "Monitor shunt site for redness, swelling, drainage, or tenderness", "Position patient as ordered after shunt placement (avoid lying on shunt side)", "Report any acute changes in neurological status immediately", "Monitor surgical wound for signs of CSF leak", "Teach families about shunt malfunction warning signs before discharge", "Maintain seizure precautions throughout hospitalization"],
  assessmentFindings: ["Infants: rapidly increasing head circumference, bulging fontanelle, setting-sun eyes, poor feeding", "Children and adults: headache worse in morning, nausea and vomiting, papilledema, decreased LOC", "NPH triad: gait disturbance (wide-based, shuffling), urinary incontinence, cognitive decline", "Post-shunt: signs of malfunction include return of pre-operative symptoms", "Post-shunt infection: fever, lethargy, irritability, wound redness"],
  signs: { left: ["Bulging fontanelle (infants)", "Increasing head circumference", "Setting-sun eyes", "Headache (worse in AM)", "Decreased LOC"], right: ["Projectile vomiting", "Papilledema", "Gait disturbance (NPH)", "Urinary incontinence (NPH)", "Cognitive decline"] },
  medications: [
    { name: "Acetazolamide (Diamox)", type: "Carbonic anhydrase inhibitor", action: "Temporarily reduces CSF production by inhibiting carbonic anhydrase in the choroid plexus", sideEffects: "Metabolic acidosis, tingling in extremities, electrolyte imbalances, kidney stones", contra: "Severe hepatic or renal impairment, hyponatremia, hypokalemia", pearl: "Used as temporizing measure to reduce CSF production while awaiting definitive surgical treatment; not effective for long-term management; monitor electrolytes and acid-base status" }
  ],
  pearls: ["In infants, increasing head circumference crossing percentile lines on growth chart is the earliest sign of hydrocephalus", "Setting-sun eyes (downward deviation) in infants indicates pressure on the tectal plate", "VP shunt malfunction can present hours to years after placement: educate families about warning signs", "Never pump the shunt valve unless specifically ordered by neurosurgery", "Normal pressure hydrocephalus is one of the few REVERSIBLE causes of dementia in the elderly", "NPH triad: Wacky (gait), Wet (incontinence), Wobbly (dementia)"],
  lifespan: { title: "Across the Lifespan", content: "Congenital hydrocephalus affects 1-2 per 1000 live births. In premature infants, intraventricular hemorrhage is the most common cause. The open fontanelles allow the skull to expand, so head circumference measurement is a crucial monitoring tool. In children, shunt-dependent hydrocephalus requires lifelong monitoring and likely multiple shunt revisions as the child grows. In elderly patients, NPH presents with the classic triad and can mimic Alzheimer disease or Parkinson disease; a positive CSF tap test (improvement in gait after large-volume LP) supports the diagnosis and predicts shunt response." },
  quiz: [
    { question: "A nurse measuring an infant's head circumference notes it has crossed from the 50th to the 90th percentile over two weeks. What should the nurse do?", options: ["Document and continue to monitor at the next routine visit", "Report immediately as this may indicate developing hydrocephalus", "Reassure the parents that head growth varies in infants", "Remeasure next month to confirm the trend"], correct: 1, rationale: "Rapid head circumference growth crossing percentile lines is the earliest sign of hydrocephalus in infants. The unfused sutures allow the skull to expand as CSF accumulates. This requires immediate reporting and likely urgent imaging (CT or ultrasound) to evaluate for hydrocephalus." },
    { question: "A patient with a VP shunt develops sudden headache, nausea, and decreased alertness. What should the nurse suspect?", options: ["Migraine headache", "Shunt malfunction with increasing ICP", "Medication side effect", "Normal post-operative recovery"], correct: 1, rationale: "The return of hydrocephalus symptoms (headache, nausea, decreased alertness) in a patient with a VP shunt strongly suggests shunt malfunction. The shunt may be obstructed, disconnected, or infected. This requires urgent evaluation with CT scan and possible shunt revision." },
    { question: "An elderly patient presents with a wide-based shuffling gait, urinary incontinence, and progressive memory problems. Which condition should the nurse recognize this triad as?", options: ["Parkinson disease", "Alzheimer disease", "Normal pressure hydrocephalus", "Stroke"], correct: 2, rationale: "The triad of gait disturbance, urinary incontinence, and dementia in an elderly patient is the classic presentation of normal pressure hydrocephalus (NPH). This is important to recognize because NPH is one of the few reversible causes of dementia. Treatment with a VP shunt can significantly improve symptoms." }
  ]
};

lessons["peds-neuro"] = {
  title: "Pediatric Neurological Conditions and Seizures",
  cellular: { title: "Pathophysiology of Pediatric Neurological Conditions", content: "The pediatric nervous system differs significantly from the adult nervous system because it is still developing. Myelination, synapse formation, and neural pathway refinement continue throughout childhood into adolescence, making the pediatric brain both more vulnerable to certain injuries and more capable of neuroplastic recovery. Understanding these developmental differences is essential for accurate pediatric neurological assessment.\n\nFebrile seizures are the most common pediatric neurological emergency, affecting 2-5% of children ages 6 months to 5 years. They occur during rapid temperature rise, typically above 38.3 degrees C (101 degrees F). The immature brain has a lower seizure threshold than the adult brain because inhibitory GABA pathways are not fully developed, and excitatory glutamate pathways are more active. Simple febrile seizures are generalized tonic-clonic seizures lasting less than 15 minutes that occur once in a 24-hour period. Complex febrile seizures are focal, last more than 15 minutes, or recur within 24 hours. Simple febrile seizures are benign and do not require anticonvulsant treatment, but they are terrifying for parents who need reassurance and education.\n\nPediatric brain tumors are the most common solid tumors in children and the leading cause of cancer-related death in children. Unlike adult brain tumors, which are predominantly supratentorial (above the tentorium), pediatric brain tumors are commonly infratentorial (posterior fossa, cerebellum, brainstem). This location explains why children often present with signs of increased ICP (from CSF obstruction at the fourth ventricle) and cerebellar dysfunction (ataxia, nystagmus, coordination problems) rather than focal cortical deficits.\n\nMeningitis in children presents differently by age. In neonates and young infants, classic signs of meningitis (nuchal rigidity, Kernig sign, Brudzinski sign) are often ABSENT. Instead, infants present with nonspecific symptoms: poor feeding, irritability or lethargy, temperature instability (fever or hypothermia), high-pitched cry, and bulging fontanelle. Bacterial meningitis is a medical emergency requiring rapid antibiotic administration.\n\nFor RPNs, pediatric neurological assessment requires age-appropriate techniques: assess fontanelles in infants (bulging = increased ICP, sunken = dehydration), use the Pediatric Glasgow Coma Scale (modified for pre-verbal children), measure head circumference at every visit in children under 2, and observe for developmental regression (loss of previously acquired skills), which is always abnormal and requires immediate investigation." },
  riskFactors: ["Age 6 months to 5 years (febrile seizures)", "Prematurity", "Family history of seizures or neurological conditions", "Recent illness or infection", "History of meningitis or encephalitis", "Congenital brain malformations", "Head trauma or non-accidental injury", "Immunocompromised state"],
  diagnostics: ["Expect temperature assessment in all pediatric patients with altered consciousness", "Monitor head circumference and plot on growth chart in children under 2", "Expect CT or MRI for new-onset seizures, focal deficits, or suspected mass", "Use Pediatric Glasgow Coma Scale for age-appropriate neurological assessment", "Expect lumbar puncture if meningitis is suspected (after ruling out raised ICP)", "Monitor developmental milestones and report any regression"],
  management: ["During seizure: protect from injury, do not restrain, time the seizure, turn to side after", "For febrile seizures: treat the fever (acetaminophen or ibuprofen after seizure resolves)", "Maintain seizure precautions with padded side rails and suction available", "Keep environment calm and minimize stimulation for neurologically impaired children", "Position appropriately based on condition (HOB elevated for raised ICP)", "Support nutrition and hydration with age-appropriate diet modifications"],
  nursingActions: ["Assess neurological status using age-appropriate tools (Pediatric GCS, fontanelle assessment)", "Monitor temperature and treat fever promptly in seizure-prone children", "Time and document all seizure activity (type, duration, behavior before and after)", "Measure head circumference and compare to previous measurements", "Assess developmental milestones and report any regression", "Educate parents about febrile seizure management and when to seek emergency care", "Maintain safety precautions appropriate to child's developmental level", "Provide emotional support to parents and family"],
  assessmentFindings: ["Febrile seizure: rapid temperature rise with generalized tonic-clonic activity, post-ictal drowsiness", "Infant meningitis: poor feeding, irritability, lethargy, high-pitched cry, bulging fontanelle", "Increased ICP in infants: bulging fontanelle, setting-sun eyes, increasing head circumference", "Brain tumor: morning headache, vomiting, ataxia, personality changes, visual disturbances", "Developmental regression: loss of previously achieved milestones"],
  signs: { left: ["Febrile seizure activity", "Bulging fontanelle", "High-pitched cry", "Poor feeding", "Developmental regression"], right: ["Setting-sun eyes", "Increased head circumference", "Ataxia and coordination problems", "Morning vomiting", "Irritability or lethargy"] },
  medications: [
    { name: "Acetaminophen", type: "Antipyretic/Analgesic", action: "Reduces fever by acting on the hypothalamic heat-regulating center", sideEffects: "Hepatotoxicity at excessive doses", contra: "Severe hepatic impairment", pearl: "Weight-based dosing in children (10-15 mg/kg every 4-6 hours, max 5 doses/day); used to manage fever in febrile seizure patients; do NOT give aspirin to children (Reye syndrome risk)" },
    { name: "Ceftriaxone", type: "Third-generation cephalosporin", action: "Inhibits bacterial cell wall synthesis; broad-spectrum coverage including common meningitis pathogens", sideEffects: "Diarrhea, rash, injection site pain", contra: "Cephalosporin allergy, neonates receiving IV calcium", pearl: "Empiric treatment for suspected bacterial meningitis pending culture results; combined with vancomycin in many protocols; administer as soon as meningitis is suspected, do not delay for LP" }
  ],
  pearls: ["Simple febrile seizures are benign and do NOT require anticonvulsant treatment; parents need reassurance", "In infants, classic meningeal signs (nuchal rigidity, Kernig, Brudzinski) are often ABSENT; look for poor feeding, irritability, bulging fontanelle", "Developmental regression (loss of previously acquired skills) is ALWAYS abnormal and requires urgent investigation", "Never give aspirin to children under 18 due to Reye syndrome risk", "Morning vomiting with headache in a child should raise concern for brain tumor until proven otherwise", "Pediatric GCS uses modified verbal and motor scales for pre-verbal children"],
  lifespan: { title: "Across the Lifespan", content: "Febrile seizures affect 2-5% of children aged 6 months to 5 years; most outgrow them by age 5. The risk of developing epilepsy after a simple febrile seizure is only 1-2%, similar to the general population. Bacterial meningitis pathogens differ by age: Group B Streptococcus and E. coli in neonates, Streptococcus pneumoniae and Neisseria meningitidis in older infants and children. Brain tumors in children under 3 years have more aggressive courses and poorer prognosis due to the limitations of radiation therapy in the developing brain." },
  quiz: [
    { question: "A 2-year-old with a temperature of 39.4 degrees C has a generalized tonic-clonic seizure lasting 90 seconds. After the seizure, the child is drowsy but recovers to baseline in 30 minutes. What should the nurse teach the parents?", options: ["The child needs to start daily anticonvulsant medication", "This is a simple febrile seizure that is usually benign; manage fever and monitor", "The child has epilepsy and will have seizures for life", "Febrile seizures cause brain damage and developmental delays"], correct: 1, rationale: "This presentation (generalized seizure lasting less than 15 minutes with quick recovery during a febrile illness in a child age 6 months to 5 years) is a simple febrile seizure. These are benign, do not cause brain damage, and do not require anticonvulsant therapy. Parents need reassurance and education about fever management and when to seek emergency care (seizure lasting more than 5 minutes, focal features, no recovery)." },
    { question: "A 4-month-old presents with poor feeding, lethargy, a high-pitched cry, and a bulging anterior fontanelle. The nurse suspects meningitis. Which assessment finding would the nurse NOT expect to find in an infant this age?", options: ["Temperature instability", "Positive Kernig sign (nuchal rigidity with knee extension)", "Irritability alternating with lethargy", "Bulging fontanelle"], correct: 1, rationale: "Classic meningeal signs such as Kernig sign and Brudzinski sign are unreliable in infants because their neck muscles are not developed enough to produce nuchal rigidity. Infant meningitis presents with nonspecific symptoms: poor feeding, irritability or lethargy, temperature instability, high-pitched cry, and bulging fontanelle." },
    { question: "A parent reports that their 18-month-old, who was previously walking and saying several words, has stopped walking and no longer speaks. What should the nurse do?", options: ["Reassure the parent that children develop at different rates", "Report immediately as developmental regression always requires urgent investigation", "Suggest the parent monitor for another month and return if no improvement", "Attribute the changes to the child's recent illness"], correct: 1, rationale: "Developmental regression (loss of previously acquired skills such as walking and speech) is ALWAYS abnormal and requires urgent investigation. It can indicate a serious neurological condition such as a neurodegenerative disease, brain tumor, metabolic disorder, or non-accidental injury. This is never normal developmental variation." }
  ]
};

lessons["trigeminal-neuralgia-rpn"] = {
  title: "Trigeminal Neuralgia",
  cellular: { title: "Pathophysiology of Trigeminal Neuralgia", content: "Trigeminal neuralgia (TN), also called tic douloureux, is a chronic pain condition affecting the trigeminal nerve (CN V) that causes sudden, severe, shock-like facial pain episodes lasting seconds to two minutes. It is often described as one of the most painful conditions known to medicine.\n\nThe trigeminal nerve has three branches: V1 (ophthalmic) supplies the forehead and upper face, V2 (maxillary) supplies the cheek and upper jaw, and V3 (mandibular) supplies the lower jaw and chin. The most common branches affected in TN are V2 and V3, producing pain in the cheek, jaw, teeth, gums, and lips. V1 is involved in less than 5% of cases.\n\nThe most common cause (80-90%) is vascular compression of the trigeminal nerve root entry zone by an aberrant arterial loop (usually the superior cerebellar artery). The pulsating artery compresses and irritates the nerve, causing focal demyelination. When the demyelinated fibers are exposed, normal sensory signals (light touch from washing the face, eating, brushing teeth) can trigger abnormal high-frequency discharges that spread to adjacent pain fibers, producing the characteristic lancinating pain.\n\nTN episodes are triggered by normally innocuous stimuli (trigger zones) such as touching the face, chewing, talking, brushing teeth, washing the face, shaving, or even a breeze on the face. The pain is strictly unilateral (bilateral in only 3% of cases), comes in paroxysms (sudden bursts), and is followed by a refractory period during which no pain can be triggered. Between attacks, the patient is pain-free.\n\nFor RPNs, nursing care focuses on identifying triggers and helping patients avoid them, ensuring proper nutrition when eating triggers pain, administering medications on time, providing emotional support (chronic severe pain causes depression and suicidal ideation), and monitoring for medication side effects. The nurse should never touch the affected side of the face without warning the patient." },
  riskFactors: ["Age over 50 years", "Female sex (slightly more common in women)", "Multiple sclerosis (demyelination of trigeminal root)", "Hypertension (associated with aberrant vessels)", "Family history of trigeminal neuralgia"],
  diagnostics: ["Expect MRI with contrast to identify vascular compression or MS plaques", "Assess pain characteristics (unilateral, lancinating, seconds to minutes)", "Identify trigger zones and activities that provoke pain", "Monitor pain severity using validated pain scales", "Expect neurological examination to rule out other causes", "Assess nutritional status if eating triggers pain"],
  management: ["Administer anticonvulsant medications as prescribed (carbamazepine is first-line)", "Help patient identify and avoid known triggers", "Ensure adequate nutrition: modify diet to soft foods on unaffected side", "Provide oral care gently with lukewarm water on unaffected side", "Protect face from cold air drafts and wind", "Monitor for depression and suicidal ideation related to chronic pain"],
  nursingActions: ["Administer carbamazepine or prescribed anticonvulsant on schedule", "Approach patient from unaffected side and warn before touching face", "Provide soft, lukewarm foods and beverages (avoid hot/cold extremes)", "Assess pain intensity and quality at each interaction", "Monitor carbamazepine levels and CBC (risk of agranulocytosis)", "Provide emotional support and assess for depression", "Educate about trigger avoidance strategies", "Maintain oral hygiene with gentle technique on unaffected side"],
  assessmentFindings: ["Sudden, severe, unilateral facial pain lasting seconds to 2 minutes", "Pain described as electric shock, stabbing, or lancinating", "Pain triggered by light touch, eating, talking, or wind on face", "Pain-free intervals between attacks", "Facial grimacing or wincing during episodes (tic douloureux)", "Weight loss from avoiding eating due to pain trigger"],
  signs: { left: ["Sudden lancinating facial pain", "Pain along V2 or V3 distribution", "Facial grimacing during episodes", "Pain triggered by light touch", "Unilateral presentation"], right: ["Pain-free intervals between attacks", "Weight loss from avoiding eating", "Depression or anxiety", "Sleep disruption", "Social isolation"] },
  medications: [
    { name: "Carbamazepine (Tegretol)", type: "Anticonvulsant", action: "Stabilizes neuronal membranes by blocking voltage-gated sodium channels, reducing the abnormal firing that produces trigeminal pain", sideEffects: "Dizziness, drowsiness, nausea, diplopia, aplastic anemia, agranulocytosis, Stevens-Johnson syndrome, hepatotoxicity", contra: "History of bone marrow suppression, MAOIs within 14 days, hepatic porphyria", pearl: "First-line treatment for trigeminal neuralgia; monitor CBC regularly (risk of life-threatening agranulocytosis); obtain baseline and periodic liver function tests; Asian patients should be tested for HLA-B*1502 allele (Stevens-Johnson risk); therapeutic level 4-12 mcg/mL" }
  ],
  pearls: ["Trigeminal neuralgia is considered one of the most painful conditions in medicine", "Carbamazepine is the first-line medication; monitor CBC for agranulocytosis", "Never touch the affected side of the face without warning the patient first", "Approach the patient from the unaffected side", "Weight loss is common because eating triggers pain: provide nutrition support", "Assess for depression and suicidal ideation: chronic severe pain has significant psychological impact"],
  quiz: [
    { question: "A patient with trigeminal neuralgia refuses to eat because chewing triggers severe facial pain. What is the best nursing intervention?", options: ["Encourage the patient to eat normally despite the pain", "Offer soft, lukewarm foods to eat on the unaffected side, timed with peak medication effect", "Insert a nasogastric tube for nutrition", "Withhold food until the pain episode resolves completely"], correct: 1, rationale: "Providing soft, room-temperature foods eaten on the unaffected side minimizes trigger stimulation while maintaining nutrition. Timing meals with peak medication effect (approximately 1-2 hours after carbamazepine dose) further reduces pain risk. NG tube is too invasive for this situation, and eating normally would trigger severe pain." },
    { question: "A nurse is providing oral care for a patient with left-sided trigeminal neuralgia. Which approach is correct?", options: ["Brush teeth normally with cold water for a thorough clean", "Use lukewarm water, approach from the right side, and clean the right side first", "Skip oral care entirely to avoid triggering pain", "Use an electric toothbrush for efficiency"], correct: 1, rationale: "Oral care should be performed gently using lukewarm water (cold triggers pain), approaching from the unaffected side (right), and cleaning the unaffected side first. Oral care cannot be skipped entirely as this leads to dental problems. Electric toothbrushes create vibration that can trigger pain." },
    { question: "A patient taking carbamazepine for trigeminal neuralgia develops a sore throat, fever, and mouth ulcers. What should the nurse do?", options: ["Administer acetaminophen for the fever and continue carbamazepine", "Report immediately and hold the medication as these may indicate agranulocytosis", "Increase the carbamazepine dose as the symptoms suggest inadequate pain control", "Schedule a routine follow-up appointment"], correct: 1, rationale: "Sore throat, fever, and mouth ulcers in a patient taking carbamazepine are potential signs of agranulocytosis (severe neutropenia), a life-threatening adverse effect. The medication should be held and an urgent CBC obtained. This is a medical emergency requiring immediate intervention." }
  ]
};

lessons["peripheral-neuropathy-basics-rpn"] = {
  title: "Peripheral Neuropathy Basics",
  cellular: { title: "Pathophysiology of Peripheral Neuropathy", content: "Peripheral neuropathy refers to damage or dysfunction of the peripheral nerves (those outside the brain and spinal cord), resulting in sensory, motor, or autonomic symptoms depending on which nerve fibers are affected. It is extremely common, affecting up to 8% of the general population and up to 50% of patients with diabetes.\n\nPeripheral nerves contain three types of fibers: sensory (carrying touch, pain, temperature, and position information from the body to the brain), motor (carrying movement commands from the brain to muscles), and autonomic (controlling involuntary functions like blood pressure, heart rate, digestion, and sweating). Neuropathy can affect any combination of these fiber types.\n\nThe two main patterns of nerve damage are axonal degeneration and demyelination. In axonal degeneration (the most common), the axon itself is damaged, typically starting at the most distal portions (the longest nerves are affected first). This produces the characteristic stocking-glove distribution where symptoms begin in the toes and feet, progress to the ankles and calves, and eventually involve the fingertips and hands. The pathophysiology involves metabolic damage to the axon from hyperglycemia (diabetic neuropathy), toxins (alcohol, chemotherapy), nutritional deficiencies (B12, thiamine), or ischemia.\n\nIn demyelinating neuropathy, the myelin sheath is damaged while the axon is preserved initially. This produces motor weakness and areflexia more prominently than sensory symptoms. Guillain-Barre syndrome is the classic acute demyelinating neuropathy.\n\nDiabetic peripheral neuropathy, the most common form, occurs through several mechanisms: hyperglycemia activates the polyol pathway, converting glucose to sorbitol which accumulates in nerve cells and causes osmotic damage. Advanced glycation end-products (AGEs) damage nerve proteins and blood vessel walls. Microvascular disease reduces blood supply to peripheral nerves (vasa nervorum), causing ischemic nerve injury.\n\nFor RPNs, the critical nursing priorities are fall prevention (patients with sensory neuropathy cannot feel their feet properly), foot care education (especially for diabetic patients who may not feel injuries), pain management (neuropathic pain responds poorly to standard analgesics), and monitoring for autonomic symptoms (orthostatic hypotension, gastroparesis, neurogenic bladder)." },
  riskFactors: ["Diabetes mellitus (most common cause)", "Chronic alcohol use (alcoholic neuropathy)", "Vitamin B12 deficiency", "Chemotherapy (platinum-based, taxanes, vinca alkaloids)", "Chronic kidney disease (uremic neuropathy)", "HIV infection", "Hypothyroidism", "Autoimmune diseases (rheumatoid arthritis, lupus)", "Hereditary conditions (Charcot-Marie-Tooth disease)"],
  diagnostics: ["Expect nerve conduction studies and EMG", "Monitor blood glucose and HbA1c (diabetic neuropathy)", "Expect B12 level, folate, and thyroid function tests", "Assess sensation using monofilament testing (10g monofilament on plantar surface)", "Assess proprioception and vibration sense", "Monitor for orthostatic blood pressure changes"],
  management: ["Optimize glycemic control in diabetic neuropathy (primary intervention)", "Implement fall precautions and mobility aids as needed", "Provide daily foot inspection education for diabetic patients", "Manage neuropathic pain with appropriate medications (gabapentin, pregabalin)", "Address nutritional deficiencies (B12 supplementation)", "Provide assistive devices for impaired fine motor skills"],
  nursingActions: ["Perform monofilament foot assessment and document findings", "Assess sensation in extremities and compare bilaterally", "Implement fall precautions for patients with impaired sensation or proprioception", "Educate about daily foot inspection, proper footwear, and never walking barefoot", "Monitor blood glucose and encourage adherence to diabetic management", "Assess for orthostatic hypotension (lying, sitting, standing blood pressures)", "Administer neuropathic pain medications as prescribed", "Assess for signs of injury that the patient may not feel (cuts, blisters, pressure injuries)"],
  assessmentFindings: ["Numbness and tingling in stocking-glove distribution (feet first, then hands)", "Burning or shooting pain in affected areas", "Loss of protective sensation (cannot feel sharp objects, temperature extremes)", "Decreased or absent deep tendon reflexes in ankles", "Impaired proprioception (difficulty with balance, especially in dark)", "Muscle weakness and wasting in severe cases", "Autonomic symptoms: orthostatic hypotension, gastroparesis, anhidrosis"],
  signs: { left: ["Numbness in feet and hands", "Burning neuropathic pain", "Tingling (paresthesias)", "Loss of sensation to monofilament", "Decreased ankle reflexes"], right: ["Impaired balance and proprioception", "Foot ulcers or injuries", "Muscle weakness and wasting", "Orthostatic hypotension", "Charcot foot deformity"] },
  medications: [
    { name: "Gabapentin (Neurontin)", type: "Anticonvulsant (neuropathic pain)", action: "Binds to voltage-gated calcium channels in the CNS, reducing the release of excitatory neurotransmitters that generate neuropathic pain signals", sideEffects: "Drowsiness, dizziness, peripheral edema, weight gain, ataxia", contra: "Known hypersensitivity; dose adjustment in renal impairment", pearl: "First-line for diabetic neuropathic pain; start low and titrate gradually; take with food; do not stop abruptly (taper over 1 week minimum); common to start at 100-300mg at bedtime and increase" },
    { name: "Pregabalin (Lyrica)", type: "Anticonvulsant (neuropathic pain)", action: "Similar to gabapentin; binds calcium channels to reduce excitatory neurotransmitter release", sideEffects: "Dizziness, somnolence, weight gain, peripheral edema, blurred vision", contra: "Known hypersensitivity; dose reduction in renal impairment", pearl: "More predictable absorption than gabapentin; also used for fibromyalgia; scheduled substance (potential for misuse); monitor for suicidal ideation" }
  ],
  pearls: ["Diabetes is the number one cause of peripheral neuropathy: glycemic control is the most important intervention", "Stocking-glove pattern: symptoms start in toes and feet (longest nerves affected first), then spread to hands", "Daily foot inspection is essential: patients cannot feel injuries, leading to undetected wounds, infections, and amputation", "Monofilament testing: inability to feel a 10g monofilament on the plantar surface indicates significant sensory loss", "Neuropathic pain does not respond well to standard analgesics (NSAIDs, acetaminophen); anticonvulsants and certain antidepressants are used", "Falls are a major risk: impaired proprioception means patients rely heavily on vision for balance and are at high risk in the dark"],
  quiz: [
    { question: "A diabetic patient cannot feel the 10g monofilament on the plantar surface of the right foot. What is the priority nursing intervention?", options: ["Document the finding and reassess at the next visit", "Implement comprehensive foot care education and daily foot inspection", "Refer for immediate surgery", "Increase the patient's pain medication"], correct: 1, rationale: "Inability to feel a 10g monofilament indicates significant sensory loss and high risk for undetected foot injuries, ulceration, infection, and ultimately amputation. The priority is educating the patient about daily foot inspection, proper footwear, never walking barefoot, and reporting any skin changes or injuries immediately." },
    { question: "A patient with peripheral neuropathy reports that burning pain in the feet is worse at night and is not relieved by acetaminophen. What medication class should the nurse anticipate being prescribed?", options: ["Opioid analgesics", "Nonsteroidal anti-inflammatory drugs", "Anticonvulsants such as gabapentin or pregabalin", "Muscle relaxants"], correct: 2, rationale: "Neuropathic pain results from nerve damage and abnormal pain signal processing, not inflammation or tissue damage. Standard analgesics (acetaminophen, NSAIDs) are ineffective. Anticonvulsants (gabapentin, pregabalin) that modulate calcium channels and reduce aberrant nerve firing are first-line treatments for neuropathic pain." },
    { question: "Why does peripheral neuropathy affect the feet before the hands?", options: ["The feet have fewer nerve endings than the hands", "The longest nerves are most vulnerable, and nerves to the feet are the longest in the body", "The feet have less blood supply than the hands", "Gravity causes toxins to accumulate in the feet"], correct: 1, rationale: "Peripheral neuropathy follows a length-dependent pattern: the longest nerves are affected first because they have the greatest metabolic demands and are most vulnerable to damage. Nerves supplying the toes and feet are the longest in the body, so they develop symptoms first. As the disease progresses, shorter nerves to the hands become affected (stocking-glove distribution)." }
  ]
};

lessons["gerd-basics-rpn"] = {
  title: "GERD (Gastroesophageal Reflux Disease)",
  cellular: { title: "Pathophysiology of GERD", content: "Gastroesophageal reflux disease (GERD) occurs when the lower esophageal sphincter (LES) fails to prevent gastric contents from refluxing into the esophagus, causing tissue damage, inflammation, and characteristic symptoms. GERD affects approximately 20% of the adult population in Western countries and is one of the most common gastrointestinal conditions nurses will encounter.\n\nThe LES is a ring of smooth muscle at the gastroesophageal junction that normally maintains a resting pressure of 10-30 mmHg, creating a barrier that prevents acidic gastric contents (pH 1-2) from entering the esophagus (which lacks the protective mucus lining that protects the stomach). In GERD, the LES tone is inappropriately low, allowing transient relaxations that permit reflux. Contributing factors include increased intra-abdominal pressure (obesity, pregnancy, ascites), delayed gastric emptying, hiatal hernia (displacement of the gastroesophageal junction above the diaphragm), and certain substances that relax the LES (caffeine, chocolate, alcohol, nicotine, fatty foods, peppermint).\n\nWhen acidic gastric contents contact the esophageal mucosa, they cause chemical injury to the squamous epithelium. Repeated acid exposure leads to inflammation (esophagitis), erosion, and potentially ulceration. Chronic GERD can cause Barrett esophagus, a condition where the normal squamous epithelium is replaced by columnar intestinal-type epithelium (intestinal metaplasia) as an adaptive response to chronic acid exposure. Barrett esophagus is a premalignant condition that increases the risk of esophageal adenocarcinoma by 30-125 times compared to the general population.\n\nGERD can also cause extraesophageal complications: chronic cough (acid irritation of the vagus nerve or microaspiration), laryngitis and hoarseness (acid damage to vocal cords), dental erosion (acid damaging tooth enamel), and asthma exacerbation (acid-triggered bronchospasm).\n\nFor RPNs, nursing management focuses on lifestyle modifications that reduce reflux (positioning, dietary changes, weight management), medication administration, and recognizing complications. The key positioning principle is that gravity helps keep gastric contents in the stomach: elevate the head of bed 30 degrees for patients with GERD, especially after meals and during sleep." },
  riskFactors: ["Obesity (increased intra-abdominal pressure)", "Pregnancy", "Hiatal hernia", "Smoking (nicotine relaxes LES)", "Alcohol consumption", "High-fat diet", "Caffeine and chocolate consumption", "Certain medications (calcium channel blockers, nitrates, anticholinergics, NSAIDs)", "Delayed gastric emptying", "Connective tissue disorders (scleroderma)"],
  diagnostics: ["Expect upper endoscopy (EGD) for persistent symptoms or complications", "Monitor symptom response to empiric PPI therapy (PPI trial)", "Expect esophageal pH monitoring for atypical presentations", "Expect barium swallow to evaluate hiatal hernia", "Monitor for alarm symptoms requiring urgent endoscopy (dysphagia, weight loss, GI bleeding, anemia)", "Expect biopsy during EGD to assess for Barrett esophagus"],
  management: ["Elevate head of bed 30 degrees (use blocks under bed frame, not just pillows)", "Avoid eating 2-3 hours before bedtime", "Eat small, frequent meals rather than large meals", "Avoid trigger foods: caffeine, chocolate, alcohol, fatty/spicy foods, citrus, tomato", "Maintain healthy weight or pursue weight loss if obese", "Avoid tight-fitting clothing around the abdomen"],
  nursingActions: ["Position patient with HOB elevated 30 degrees, especially after meals", "Administer PPIs as prescribed (30 minutes before first meal of the day)", "Educate about dietary modifications and trigger avoidance", "Assess for alarm symptoms (difficulty swallowing, unintended weight loss, GI bleeding)", "Monitor medication effectiveness and side effects", "Encourage smoking cessation and alcohol reduction", "Educate about avoiding lying down for 2-3 hours after eating", "Assess nutritional status and BMI"],
  assessmentFindings: ["Heartburn (pyrosis): burning sensation in the substernal area, worse after meals and when lying down", "Regurgitation of acidic or bitter fluid into the mouth", "Dysphagia (difficulty swallowing) suggesting complications", "Chronic cough, especially at night", "Hoarseness or sore throat (laryngeal irritation)", "Dental erosion from chronic acid exposure", "Epigastric discomfort or chest pain (must differentiate from cardiac pain)"],
  signs: { left: ["Heartburn (substernal burning)", "Acid regurgitation", "Dysphagia", "Chronic cough", "Hoarseness"], right: ["Water brash (excessive salivation)", "Chest pain (non-cardiac)", "Dental erosion", "Nausea", "Belching"] },
  medications: [
    { name: "Omeprazole (Prilosec)", type: "Proton pump inhibitor (PPI)", action: "Irreversibly blocks the hydrogen-potassium ATPase pump in parietal cells, suppressing gastric acid secretion by up to 90%", sideEffects: "Headache, diarrhea, abdominal pain, vitamin B12 and magnesium deficiency with long-term use, increased C. difficile and pneumonia risk, potential bone fracture risk", contra: "Known hypersensitivity to PPIs", pearl: "Take 30 minutes before first meal for maximum effectiveness; long-term use requires periodic reassessment and monitoring for B12 and magnesium levels; step-down to H2 blockers or discontinue when possible" },
    { name: "Famotidine (Pepcid)", type: "H2 receptor antagonist", action: "Blocks histamine H2 receptors on parietal cells, reducing gastric acid secretion by approximately 70%", sideEffects: "Headache, dizziness, constipation or diarrhea", contra: "Known hypersensitivity", pearl: "Less potent than PPIs but fewer long-term side effects; good for mild symptoms or step-down from PPI therapy; can be taken as needed for breakthrough symptoms" }
  ],
  pearls: ["PPIs are most effective when taken 30 minutes before the first meal of the day", "Elevate the HEAD OF BED with blocks, not just extra pillows (pillows cause neck flexion without raising the esophagus above the stomach)", "Chest pain from GERD can mimic cardiac pain: cardiac causes must be ruled out first", "Barrett esophagus is a premalignant condition requiring endoscopic surveillance", "Long-term PPI use requires monitoring for B12 deficiency, magnesium depletion, and bone health", "Alarm symptoms (dysphagia, weight loss, GI bleeding, anemia) require urgent endoscopy to rule out malignancy"],
  quiz: [
    { question: "A patient with GERD asks why they need to elevate the head of their bed instead of just using extra pillows. What should the nurse explain?", options: ["Pillows are equally effective; either method works", "Pillows only flex the neck without raising the esophagus above the stomach level, which is needed to prevent reflux by gravity", "Pillows are more comfortable and preferred over bed elevation", "Bed elevation is only needed for severe GERD, not mild cases"], correct: 1, rationale: "Extra pillows flex the neck and upper back but do not adequately elevate the esophagus above the stomach to prevent reflux. Elevating the entire head of the bed 6-8 inches using blocks under the bed frame legs uses gravity to keep gastric contents in the stomach throughout the night." },
    { question: "A nurse is educating a patient about when to take omeprazole. What is the correct timing?", options: ["At bedtime to suppress acid production overnight", "30 minutes before the first meal of the day", "Immediately after eating to neutralize acid", "Only when heartburn symptoms occur"], correct: 1, rationale: "PPIs like omeprazole are prodrugs activated by acid. They are most effective when parietal cells are actively secreting acid, which occurs during a meal. Taking the PPI 30 minutes before eating allows the drug to be absorbed and present when parietal cells activate, providing maximum acid suppression." },
    { question: "A patient with chronic GERD reports new difficulty swallowing solid foods and unintended weight loss of 10 pounds over 2 months. What should the nurse recognize?", options: ["Normal progression of GERD symptoms", "Alarm symptoms requiring urgent endoscopy to rule out complications including malignancy", "Side effects of PPI medication", "Symptoms of anxiety causing globus sensation"], correct: 1, rationale: "Dysphagia (difficulty swallowing) and unintended weight loss in a patient with chronic GERD are alarm symptoms that could indicate esophageal stricture, Barrett esophagus with dysplasia, or esophageal adenocarcinoma. These require urgent upper endoscopy for evaluation and biopsy." }
  ]
};

lessons["peptic-ulcer-basics-rpn"] = {
  title: "Peptic Ulcer Disease Basics",
  cellular: { title: "Pathophysiology of Peptic Ulcer Disease", content: "Peptic ulcer disease (PUD) involves the erosion of the mucosal lining of the stomach (gastric ulcer) or duodenum (duodenal ulcer), creating a crater that extends through the muscularis mucosae. Understanding the balance between protective and aggressive factors in the GI tract explains why ulcers form, the different presentations of gastric vs duodenal ulcers, and the rationale for treatment.\n\nThe gastric mucosa is normally protected by several mechanisms: a thick mucus-bicarbonate barrier that neutralizes acid at the epithelial surface, rapid epithelial cell turnover (the entire gastric lining is replaced every 3-5 days), adequate mucosal blood flow that removes acid and delivers nutrients for repair, and prostaglandin production that stimulates mucus and bicarbonate secretion. Ulcers form when aggressive factors (gastric acid, pepsin) overwhelm these protective mechanisms.\n\nThe two primary causes of PUD are Helicobacter pylori infection (responsible for 60-70% of gastric ulcers and 90% of duodenal ulcers) and NSAID use (including aspirin). H. pylori is a gram-negative bacterium that survives in the acidic gastric environment by producing urease, which converts urea to ammonia, creating a protective alkaline microenvironment around the bacteria. H. pylori damages the mucosa through direct toxin production (CagA and VacA proteins), stimulation of inflammatory cytokines, and disruption of the mucus barrier. NSAIDs inhibit cyclooxygenase-1 (COX-1), which reduces prostaglandin synthesis, leading to decreased mucus and bicarbonate production, reduced mucosal blood flow, and impaired epithelial repair.\n\nGastric ulcers and duodenal ulcers present differently. Gastric ulcer pain typically occurs 30-60 minutes after eating (food stimulates acid production into the damaged stomach), and patients may lose weight because they avoid eating to prevent pain. Duodenal ulcer pain typically occurs 2-3 hours after eating and at night (when the stomach is empty and acid flows into the duodenum without food buffering), and patients may gain weight because eating temporarily relieves pain.\n\nLife-threatening complications include hemorrhage (most common, presenting as hematemesis or melena), perforation (sudden severe abdominal pain, rigid abdomen, free air on X-ray), and gastric outlet obstruction (from chronic scarring, causing persistent vomiting).\n\nFor RPNs, key responsibilities include monitoring for signs of GI bleeding (hematemesis, melena, tachycardia, hypotension), administering medications on schedule, educating about NSAID avoidance, and ensuring compliance with H. pylori eradication therapy." },
  riskFactors: ["Helicobacter pylori infection", "Chronic NSAID or aspirin use", "Smoking (impairs mucosal blood flow and healing)", "Alcohol use (direct mucosal irritation)", "Psychological stress (physiological stress ulcers in critically ill patients)", "Family history of PUD", "Zollinger-Ellison syndrome (gastrin-producing tumor)", "Blood type O (slightly increased H. pylori susceptibility)"],
  diagnostics: ["Expect upper endoscopy (EGD) for visualization and biopsy", "Expect H. pylori testing (urea breath test, stool antigen, or biopsy)", "Monitor CBC for anemia (chronic GI blood loss)", "Assess stool for occult blood (guaiac test)", "Expect serum gastrin level if Zollinger-Ellison syndrome suspected", "Monitor vital signs for signs of hemorrhage"],
  management: ["Administer PPI therapy as prescribed to reduce acid production", "Complete H. pylori triple or quadruple therapy if positive", "Avoid all NSAIDs and aspirin during treatment", "Avoid smoking, alcohol, and caffeine during healing", "Eat small, frequent meals; avoid foods that worsen symptoms", "Report any signs of GI bleeding immediately (black tarry stool, vomiting blood)"],
  nursingActions: ["Monitor for signs of GI bleeding: hematemesis, melena, tachycardia, hypotension, pallor", "Administer prescribed PPI and H. pylori eradication therapy on schedule", "Test stool for occult blood as ordered", "Educate about NSAID avoidance and safe pain alternatives (acetaminophen)", "Assess pain pattern (timing relative to meals helps distinguish gastric from duodenal)", "Monitor intake and output and nutritional status", "Report any sudden severe abdominal pain or abdominal rigidity (possible perforation)", "Educate about completing the full course of H. pylori treatment"],
  assessmentFindings: ["Epigastric pain (burning, gnawing quality)", "Gastric ulcer: pain worse with eating (30-60 min after meals)", "Duodenal ulcer: pain 2-3 hours after meals and at night, relieved by eating", "Nausea with or without vomiting", "Signs of GI bleeding: hematemesis (coffee-ground or bright red emesis), melena (black tarry stool)", "Weight loss (gastric ulcer) or weight gain (duodenal ulcer)", "Abdominal tenderness on palpation"],
  signs: { left: ["Epigastric burning pain", "Nausea", "Bloating", "Early satiety (gastric)", "Weight changes"], right: ["Hematemesis (coffee-ground emesis)", "Melena (black tarry stool)", "Tachycardia (if bleeding)", "Abdominal tenderness", "Night pain (duodenal)"] },
  medications: [
    { name: "Omeprazole (Prilosec)", type: "Proton pump inhibitor", action: "Irreversibly blocks H+/K+ ATPase pump in parietal cells, reducing acid secretion by 90%, allowing ulcer healing", sideEffects: "Headache, diarrhea, nausea, B12 and magnesium deficiency with long-term use", contra: "PPI hypersensitivity", pearl: "Take 30 min before meals; standard ulcer healing course is 4-8 weeks; must be combined with antibiotics for H. pylori eradication" },
    { name: "Amoxicillin + Clarithromycin (Triple Therapy)", type: "Antibiotic combination", action: "Amoxicillin inhibits cell wall synthesis, clarithromycin inhibits protein synthesis; together with PPI they eradicate H. pylori", sideEffects: "Diarrhea, taste changes (clarithromycin), nausea, allergic reaction (amoxicillin)", contra: "Penicillin allergy (for amoxicillin), QT prolongation (clarithromycin)", pearl: "Triple therapy (PPI + amoxicillin + clarithromycin) for 14 days is standard; compliance is critical: must complete full course to prevent resistance; confirm eradication with follow-up testing" }
  ],
  pearls: ["H. pylori causes most ulcers; NSAIDs cause most of the rest", "Gastric ulcer: pain WITH eating; Duodenal ulcer: pain BETWEEN meals (2-3 hours after)", "Black tarry stool (melena) = upper GI bleeding until proven otherwise", "Coffee-ground emesis indicates blood that has been partially digested by gastric acid", "Never give NSAIDs to a patient with active PUD; recommend acetaminophen for pain", "Completing the full H. pylori eradication course is critical: partial treatment breeds resistance"],
  quiz: [
    { question: "A patient reports burning epigastric pain that occurs 2-3 hours after meals and wakes them at night, relieved by eating crackers. Where is the ulcer most likely located?", options: ["Stomach (gastric ulcer)", "Duodenum (duodenal ulcer)", "Esophagus", "Jejunum"], correct: 1, rationale: "Pain occurring 2-3 hours after meals and at night, relieved by eating, is characteristic of duodenal ulcers. When the stomach empties acid into the duodenum without food to buffer it, pain occurs. Eating provides temporary relief because food buffers the acid. Gastric ulcer pain typically occurs within 30-60 minutes after eating." },
    { question: "A nurse notes that a patient with a history of peptic ulcer disease has black, tarry, foul-smelling stools. What should the nurse suspect and do?", options: ["Constipation requiring stool softener", "Upper GI bleeding (melena) requiring immediate reporting", "Side effect of iron supplements", "Normal stool variation"], correct: 1, rationale: "Black, tarry, foul-smelling stool (melena) indicates upper GI bleeding. Blood from the upper GI tract is partially digested by gastric acid and intestinal bacteria, producing the characteristic black, tarry appearance and foul smell. This requires immediate reporting, vital sign monitoring, and preparation for potential emergency intervention." },
    { question: "Which over-the-counter medication should a patient with a peptic ulcer AVOID?", options: ["Acetaminophen (Tylenol)", "Ibuprofen (Advil)", "Calcium carbonate (Tums)", "Famotidine (Pepcid)"], correct: 1, rationale: "Ibuprofen is an NSAID that inhibits prostaglandin synthesis, reducing the protective mucus and bicarbonate barrier in the stomach and potentially worsening or reactivating the ulcer. Patients with PUD should use acetaminophen for pain relief instead. Calcium carbonate and famotidine actually help reduce acid exposure." }
  ]
};

